import React, { useState, useEffect } from 'react';
import { ThemeProvider, useTheme } from './ThemeContext';
import Navbar from './components/Navbar';
import Hero from './components/Hero';
import About from './components/About';
import Projects from './components/Projects';
import GitHubRepos from './components/GitHubRepos';
import Contact from './components/Contact';
import Footer from './components/Footer';

const Loader = () => (
    <div style={{
        position: 'fixed', inset: 0, zIndex: 9999,
        display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center',
        gap: 18,
        background: '#07091a',
    }}>
        <div style={{ position: 'relative', width: 56, height: 56 }}>
            <svg style={{ position: 'absolute', inset: 0, animation: 'spin 1s linear infinite' }}
                width="56" height="56" viewBox="0 0 56 56">
                <circle cx="28" cy="28" r="24" fill="none"
                    stroke="rgba(124,58,237,0.1)" strokeWidth="2.5" />
                <circle cx="28" cy="28" r="24" fill="none"
                    stroke="url(#lg)" strokeWidth="2.5"
                    strokeDasharray="38 114" strokeLinecap="round" />
                <defs>
                    <linearGradient id="lg" x1="0%" y1="0%" x2="100%" y2="0%">
                        <stop offset="0%" stopColor="#7c3aed" />
                        <stop offset="100%" stopColor="#3b82f6" />
                    </linearGradient>
                </defs>
            </svg>
            <div style={{
                position: 'absolute', inset: 10, borderRadius: 10,
                background: 'linear-gradient(135deg, #7c3aed, #4f46e5)',
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                fontSize: 16, fontWeight: 800, color: 'white',
                fontFamily: 'Plus Jakarta Sans, sans-serif',
                boxShadow: '0 0 20px rgba(124,58,237,0.5)',
                letterSpacing: '-0.5px',
            }}>B</div>
        </div>
        <span style={{
            fontFamily: 'Inter, sans-serif', fontSize: 11, fontWeight: 600,
            color: 'rgba(148,163,184,0.45)', letterSpacing: 4, textTransform: 'uppercase',
            animation: 'pulse 1.5s ease-in-out infinite',
        }}>Loading</span>
        <style>{`
            @keyframes spin { to { transform: rotate(360deg); } }
            @keyframes pulse { 0%,100%{opacity:.35} 50%{opacity:1} }
        `}</style>
    </div>
);

const AppContent = () => {
    const { isDark } = useTheme();
    const [loading, setLoading] = useState(true);

    useEffect(() => {
        const t = setTimeout(() => setLoading(false), 1600);
        return () => clearTimeout(t);
    }, []);

    return (
        <>
            <div style={{
                opacity: loading ? 1 : 0,
                pointerEvents: loading ? 'all' : 'none',
                transition: 'opacity 0.5s ease',
                position: 'fixed', inset: 0, zIndex: 9999,
            }}>
                <Loader />
            </div>

            <div style={{
                minHeight: '100vh',
                background: isDark
                    ? 'radial-gradient(ellipse 90% 55% at 15% 0%, rgba(124,58,237,0.07) 0%, transparent 65%), radial-gradient(ellipse 70% 45% at 85% 85%, rgba(59,130,246,0.05) 0%, transparent 65%), #07091a'
                    : 'radial-gradient(ellipse 80% 50% at 15% 0%, rgba(109,40,217,0.07) 0%, transparent 65%), radial-gradient(ellipse 60% 40% at 85% 80%, rgba(59,130,246,0.04) 0%, transparent 65%), #f5f3ff',
                transition: 'background 0.4s ease',
                display: 'flex',
                flexDirection: 'column',
                overflow: 'hidden',
            }}>
                <Navbar />
                <main style={{ flex: 1 }}>
                    <Hero />
                    <About />
                    <Projects />
                    <GitHubRepos />
                    <Contact />
                </main>
                <Footer />
            </div>
        </>
    );
};

const App = () => (
    <ThemeProvider>
        <AppContent />
    </ThemeProvider>
);

export default App;