import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { FiCheckCircle, FiAlertCircle, FiSend, FiGithub, FiLinkedin, FiMail, FiMapPin } from 'react-icons/fi';
import { useTheme } from '../ThemeContext';

const cv = { hidden: { opacity: 0 }, visible: { opacity: 1, transition: { staggerChildren: 0.09 } } };
const ci = { hidden: { y: 18, opacity: 0 }, visible: { y: 0, opacity: 1, transition: { type: 'spring', stiffness: 85, damping: 16 } } };

const contactInfo = [
    { icon: <FiMail size={17} />,     label: 'Email',    value: 'barakusuma911@gmail.com',              href: 'mailto:barakusuma911@gmail.com', color: '#7c3aed' },
    { icon: <FiGithub size={17} />,   label: 'GitHub',   value: 'github.com/BekaGensss',                href: 'https://github.com/BekaGensss',             color: '#6366f1' },
    { icon: <FiLinkedin size={17} />, label: 'LinkedIn', value: 'linkedin.com/in/bara-kusuma',          href: 'https://id.linkedin.com/in/bara-kusuma-707067294', color: '#0ea5e9' },
    { icon: <FiMapPin size={17} />,   label: 'Lokasi',   value: 'Indonesia',                            href: null,                                        color: '#10b981' },
];

const Contact = () => {
    const { theme } = useTheme();
    const [formData, setFormData] = useState({ name: '', email: '', message: '' });
    const [errors,   setErrors]   = useState({});
    const [submitted, setSubmitted] = useState(false);
    const [loading,  setLoading]  = useState(false);

    const handleChange = e => {
        const { name, value } = e.target;
        setFormData(p => ({ ...p, [name]: value }));
        if (errors[name]) setErrors(p => ({ ...p, [name]: '' }));
    };

    const validate = () => {
        const e = {};
        if (!formData.name.trim())    e.name = 'Nama wajib diisi.';
        if (!formData.email.trim())   e.email = 'Email wajib diisi.';
        else if (!/\S+@\S+\.\S+/.test(formData.email)) e.email = 'Format email tidak valid.';
        if (!formData.message.trim()) e.message = 'Pesan wajib diisi.';
        setErrors(e);
        return Object.keys(e).length === 0;
    };

    const handleSubmit = async e => {
        e.preventDefault();
        if (!validate()) return;
        setLoading(true);
        try {
            const res = await fetch('https://getform.io/f/bjjrrgrb', {
                method: 'POST',
                body: JSON.stringify(formData),
                headers: { 'Content-Type': 'application/json', Accept: 'application/json' },
            });
            if (res.ok) {
                setSubmitted(true);
                setFormData({ name: '', email: '', message: '' });
                setTimeout(() => setSubmitted(false), 6000);
            } else {
                alert('Terjadi kesalahan. Coba lagi.');
            }
        } catch {
            alert('Gagal terhubung ke server.');
        } finally {
            setLoading(false);
        }
    };

    return (
        <section id="contact" style={{ padding: 'clamp(56px,9vh,88px) 0', position: 'relative' }}>
            <div style={{
                width: '100%', height: 1,
                background: `linear-gradient(90deg, transparent, ${theme.divider}, transparent)`,
                marginBottom: 'clamp(36px,5vh,56px)',
            }} />

            <div style={{ maxWidth: 1200, margin: '0 auto', padding: '0 20px' }}>

                {/* Header */}
                <motion.div
                    initial={{ y: 20, opacity: 0 }}
                    whileInView={{ y: 0, opacity: 1 }}
                    transition={{ duration: 0.55 }}
                    viewport={{ once: true }}
                    style={{ textAlign: 'center', marginBottom: 'clamp(28px,4vh,48px)' }}
                >
                    <span className="section-tag">Kontak</span>
                    <h2 style={{
                        fontFamily: 'Plus Jakarta Sans, sans-serif',
                        fontSize: 'clamp(1.7rem, 4vw, 2.6rem)', fontWeight: 800,
                        color: theme.textPrimary, letterSpacing: '-0.5px',
                        marginBottom: 12, lineHeight: 1.15,
                    }}>
                        Mari{' '}
                        <span style={{
                            background: 'linear-gradient(135deg, #a78bfa, #818cf8, #38bdf8)',
                            WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text',
                        }}>Berkolaborasi</span>
                    </h2>
                    <p style={{ fontSize: 'clamp(13.5px,1.8vw,15px)', color: theme.textSecondary, maxWidth: 460, margin: '0 auto' }}>
                        Ada ide proyek atau ingin berdiskusi? Saya selalu terbuka untuk peluang baru.
                    </p>
                </motion.div>

                {/* Two column */}
                <motion.div
                    initial="hidden"
                    whileInView="visible"
                    variants={cv}
                    viewport={{ once: true, amount: 0.1 }}
                    style={{
                        display: 'grid',
                        gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))',
                        gap: 40, alignItems: 'start',
                    }}
                >
                    {/* Left */}
                    <motion.div variants={ci}>
                        <h3 style={{
                            fontFamily: 'Plus Jakarta Sans, sans-serif',
                            fontSize: 19, fontWeight: 700, color: theme.textPrimary, marginBottom: 6,
                        }}>Hubungi Langsung</h3>
                        <p style={{ fontSize: 14, color: theme.textSecondary, lineHeight: 1.65, marginBottom: 24 }}>
                            Pilih cara yang paling nyaman untuk Anda. Saya biasanya membalas dalam 24 jam.
                        </p>

                        <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                            {contactInfo.map(item => (
                                <motion.div key={item.label} variants={ci}>
                                    {item.href ? (
                                        <a href={item.href}
                                            target={item.href.startsWith('http') ? '_blank' : undefined}
                                            rel="noopener noreferrer"
                                            style={{ textDecoration: 'none', display: 'block' }}
                                        >
                                            <ContactCard item={item} theme={theme} />
                                        </a>
                                    ) : (
                                        <ContactCard item={item} theme={theme} />
                                    )}
                                </motion.div>
                            ))}
                        </div>
                    </motion.div>

                    {/* Right: Form */}
                    <motion.div variants={ci}>
                        {submitted && (
                            <motion.div
                                initial={{ y: -8, opacity: 0, scale: 0.97 }}
                                animate={{ y: 0, opacity: 1, scale: 1 }}
                                style={{
                                    padding: '14px 18px', borderRadius: 10, marginBottom: 16,
                                    background: 'rgba(34,197,94,0.07)',
                                    border: '1px solid rgba(34,197,94,0.25)',
                                    display: 'flex', alignItems: 'center', gap: 10,
                                }}
                            >
                                <FiCheckCircle size={18} style={{ color: '#22c55e', flexShrink: 0 }} />
                                <div>
                                    <div style={{ fontSize: 13.5, fontWeight: 600, color: '#86efac' }}>Pesan terkirim!</div>
                                    <div style={{ fontSize: 12.5, color: theme.textMuted, marginTop: 1 }}>Saya akan segera membalas.</div>
                                </div>
                            </motion.div>
                        )}

                        <form onSubmit={handleSubmit} style={{
                            padding: 'clamp(20px,3vw,28px)',
                            borderRadius: 18, background: theme.bgCard,
                            border: `1px solid ${theme.border}`, backdropFilter: 'blur(12px)',
                        }}>
                            {[
                                { id: 'name',    label: 'Nama Lengkap', type: 'text',  placeholder: 'John Doe' },
                                { id: 'email',   label: 'Alamat Email', type: 'email', placeholder: 'john@example.com' },
                            ].map(field => (
                                <div key={field.id} style={{ marginBottom: 16 }}>
                                    <label htmlFor={field.id} style={{
                                        display: 'block', fontSize: 13, fontWeight: 600,
                                        color: theme.textPrimary, marginBottom: 6,
                                    }}>{field.label}</label>
                                    <input
                                        id={field.id} type={field.type} name={field.id}
                                        value={formData[field.id]} onChange={handleChange}
                                        placeholder={field.placeholder}
                                        className={`form-input ${errors[field.id] ? 'error' : ''}`}
                                        style={{ background: theme.inputBg, borderColor: errors[field.id] ? '#f87171' : theme.inputBorder, color: theme.inputText }}
                                    />
                                    {errors[field.id] && (
                                        <p style={{ marginTop: 6, fontSize: 12, color: '#f87171', display: 'flex', alignItems: 'center', gap: 5 }}>
                                            <FiAlertCircle size={12} /> {errors[field.id]}
                                        </p>
                                    )}
                                </div>
                            ))}

                            <div style={{ marginBottom: 22 }}>
                                <label htmlFor="message" style={{
                                    display: 'block', fontSize: 13, fontWeight: 600,
                                    color: theme.textPrimary, marginBottom: 6,
                                }}>Pesan</label>
                                <textarea
                                    id="message" name="message" rows={5}
                                    value={formData.message} onChange={handleChange}
                                    placeholder="Halo Bara, saya ingin berdiskusi mengenai..."
                                    className={`form-input ${errors.message ? 'error' : ''}`}
                                    style={{ resize: 'vertical', minHeight: 110, background: theme.inputBg, borderColor: errors.message ? '#f87171' : theme.inputBorder, color: theme.inputText }}
                                />
                                {errors.message && (
                                    <p style={{ marginTop: 6, fontSize: 12, color: '#f87171', display: 'flex', alignItems: 'center', gap: 5 }}>
                                        <FiAlertCircle size={12} /> {errors.message}
                                    </p>
                                )}
                            </div>

                            <button type="submit" disabled={loading} className="btn-primary"
                                style={{ width: '100%', justifyContent: 'center', opacity: loading ? 0.7 : 1 }}>
                                {loading ? (
                                    <>
                                        <span style={{ display: 'inline-block', width: 14, height: 14, border: '2px solid rgba(255,255,255,0.3)', borderTopColor: 'white', borderRadius: '50%', animation: 'spin 0.7s linear infinite' }} />
                                        <span>Mengirim...</span>
                                    </>
                                ) : (
                                    <>
                                        <span>Kirim Pesan</span>
                                        <FiSend size={14} />
                                    </>
                                )}
                            </button>
                            <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
                        </form>
                    </motion.div>
                </motion.div>
            </div>
        </section>
    );
};

const ContactCard = ({ item, theme }) => (
    <div style={{
        padding: '12px 16px', borderRadius: 12,
        background: theme.bgCard, border: `1px solid ${theme.border}`,
        display: 'flex', alignItems: 'center', gap: 12,
        transition: 'all 0.25s ease', cursor: item.href ? 'pointer' : 'default',
    }}
        onMouseEnter={e => {
            if (item.href) {
                e.currentTarget.style.background = `${item.color}0e`;
                e.currentTarget.style.borderColor = `${item.color}30`;
                e.currentTarget.style.transform = 'translateX(4px)';
            }
        }}
        onMouseLeave={e => {
            e.currentTarget.style.background = theme.bgCard;
            e.currentTarget.style.borderColor = theme.border;
            e.currentTarget.style.transform = 'translateX(0)';
        }}
    >
        <div style={{
            width: 38, height: 38, borderRadius: 10,
            background: `${item.color}16`, border: `1px solid ${item.color}28`,
            display: 'flex', alignItems: 'center', justifyContent: 'center',
            color: item.color, flexShrink: 0,
        }}>
            {item.icon}
        </div>
        <div>
            <div style={{ fontSize: 11, color: theme.textMuted, fontWeight: 600, textTransform: 'uppercase', letterSpacing: 0.8, marginBottom: 1 }}>
                {item.label}
            </div>
            <div style={{ fontSize: 13.5, color: theme.textPrimary, fontWeight: 500 }}>
                {item.value}
            </div>
        </div>
    </div>
);

export default Contact;