import React, { useState, useEffect } from 'react';
import { FiChevronUp, FiGithub, FiLinkedin, FiHeart } from 'react-icons/fi';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme } from '../ThemeContext';

const navLinks = [
    { href: '#home',     label: 'Home' },
    { href: '#about',    label: 'Tentang' },
    { href: '#projects', label: 'Proyek' },
    { href: '#contact',  label: 'Kontak' },
];

const socialLinks = [
    { href: 'https://github.com/BekaGensss',                    icon: <FiGithub size={16} />,   label: 'GitHub'   },
    { href: 'https://id.linkedin.com/in/bara-kusuma-707067294', icon: <FiLinkedin size={16} />, label: 'LinkedIn' },
];

const Footer = () => {
    const { theme } = useTheme();
    const [showScroll, setShowScroll] = useState(false);

    useEffect(() => {
        const onScroll = () => setShowScroll(window.scrollY > 400);
        window.addEventListener('scroll', onScroll, { passive: true });
        return () => window.removeEventListener('scroll', onScroll);
    }, []);

    const scrollTop = () => window.scrollTo({ top: 0, behavior: 'smooth' });

    return (
        <footer style={{
            background: theme.navBg,
            borderTop: `1px solid ${theme.border}`,
            padding: '40px 0 28px',
            position: 'relative',
        }}>
            <div style={{ maxWidth: 1200, margin: '0 auto', padding: '0 20px' }}>

                {/* Top row */}
                <div style={{
                    display: 'flex', flexWrap: 'wrap', justifyContent: 'space-between',
                    alignItems: 'center', gap: 20,
                    marginBottom: 28, paddingBottom: 24,
                    borderBottom: `1px solid ${theme.divider}`,
                }}>
                    {/* Brand */}
                    <div>
                        <div style={{ display: 'flex', alignItems: 'center', gap: 9, marginBottom: 8 }}>
                            <div style={{
                                width: 30, height: 30, borderRadius: 8,
                                background: 'linear-gradient(135deg, #7c3aed, #4f46e5)',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                fontSize: 13, fontWeight: 800, color: 'white',
                                fontFamily: 'Plus Jakarta Sans, sans-serif',
                                boxShadow: '0 3px 12px rgba(124,58,237,0.3)',
                            }}>B</div>
                            <span style={{ fontFamily: 'Plus Jakarta Sans, sans-serif', fontWeight: 700, fontSize: 16, color: theme.textPrimary }}>
                                Bara<span style={{ color: theme.accentText }}>.dev</span>
                            </span>
                        </div>
                        <p style={{ fontSize: 13, color: theme.textSecondary, maxWidth: 220, lineHeight: 1.6 }}>
                            Membangun pengalaman digital yang modern dan berkesan.
                        </p>
                    </div>

                    {/* Nav */}
                    <nav aria-label="Footer navigation">
                        <div style={{ display: 'flex', flexWrap: 'wrap', gap: '6px 20px', justifyContent: 'center' }}>
                            {navLinks.map(link => (
                                <a key={link.href} href={link.href}
                                    onClick={e => { e.preventDefault(); document.querySelector(link.href)?.scrollIntoView({ behavior: 'smooth' }); }}
                                    style={{ fontSize: 13.5, fontWeight: 500, color: theme.textSecondary, textDecoration: 'none', transition: 'color 0.25s ease' }}
                                    onMouseEnter={e => e.currentTarget.style.color = theme.accentText}
                                    onMouseLeave={e => e.currentTarget.style.color = theme.textSecondary}
                                >{link.label}</a>
                            ))}
                        </div>
                    </nav>

                    {/* Socials */}
                    <div style={{ display: 'flex', gap: 8 }}>
                        {socialLinks.map(s => (
                            <a key={s.label} href={s.href} target="_blank" rel="noopener noreferrer" aria-label={s.label}
                                style={{
                                    width: 36, height: 36, borderRadius: 9,
                                    background: theme.bgCard, border: `1px solid ${theme.border}`,
                                    display: 'flex', alignItems: 'center', justifyContent: 'center',
                                    color: theme.textMuted, textDecoration: 'none', transition: 'all 0.25s ease',
                                }}
                                onMouseEnter={e => {
                                    e.currentTarget.style.background = theme.accentBg;
                                    e.currentTarget.style.borderColor = theme.accentBorder;
                                    e.currentTarget.style.color = theme.accentText;
                                    e.currentTarget.style.transform = 'translateY(-2px)';
                                }}
                                onMouseLeave={e => {
                                    e.currentTarget.style.background = theme.bgCard;
                                    e.currentTarget.style.borderColor = theme.border;
                                    e.currentTarget.style.color = theme.textMuted;
                                    e.currentTarget.style.transform = 'translateY(0)';
                                }}
                            >{s.icon}</a>
                        ))}
                    </div>
                </div>

                {/* Bottom row */}
                <div style={{ display: 'flex', flexWrap: 'wrap', justifyContent: 'space-between', alignItems: 'center', gap: 10 }}>
                    <p style={{ fontSize: 12.5, color: theme.textMuted }}>
                        &copy; {new Date().getFullYear()} Bara Kusuma. Semua hak dilindungi.
                    </p>
                    <p style={{ fontSize: 12.5, color: theme.textMuted, display: 'flex', alignItems: 'center', gap: 5 }}>
                        Dibuat dengan <FiHeart size={11} style={{ color: '#7c3aed' }} /> menggunakan React
                    </p>
                </div>
            </div>

            {/* Scroll-to-top */}
            <AnimatePresence>
                {showScroll && (
                    <motion.button
                        key="scroll-top"
                        initial={{ scale: 0, opacity: 0 }}
                        animate={{ scale: 1, opacity: 1 }}
                        exit={{ scale: 0, opacity: 0 }}
                        onClick={scrollTop}
                        aria-label="Kembali ke atas"
                        style={{
                            position: 'fixed', bottom: 24, right: 20,
                            width: 42, height: 42, borderRadius: 12,
                            background: 'linear-gradient(135deg, #7c3aed, #4f46e5)',
                            border: 'none', display: 'flex', alignItems: 'center', justifyContent: 'center',
                            color: 'white', cursor: 'pointer', zIndex: 50,
                            boxShadow: '0 6px 20px rgba(124,58,237,0.45)',
                            transition: 'all 0.25s ease',
                        }}
                        whileHover={{ y: -3, boxShadow: '0 10px 28px rgba(124,58,237,0.55)' }}
                        whileTap={{ scale: 0.9 }}
                    >
                        <FiChevronUp size={20} />
                    </motion.button>
                )}
            </AnimatePresence>
        </footer>
    );
};

export default Footer;