import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FiSun, FiMoon, FiMenu, FiX } from 'react-icons/fi';
import { useTheme } from '../ThemeContext';

const navLinks = [
    { href: '#home',     label: 'Home' },
    { href: '#about',    label: 'Tentang' },
    { href: '#projects', label: 'Proyek' },
    { href: '#github',   label: 'GitHub' },
    { href: '#contact',  label: 'Kontak' },
];

const scrollTo = (href, cb) => {
    const id = href.replace('#', '');
    const el = document.getElementById(id);
    if (el) {
        const top = el.getBoundingClientRect().top + window.pageYOffset - 68;
        window.scrollTo({ top, behavior: 'smooth' });
    }
    if (cb) cb();
};

const Navbar = () => {
    const { isDark, theme, toggleTheme } = useTheme();
    const [menuOpen, setMenuOpen] = useState(false);
    const [scrolled, setScrolled] = useState(false);
    const [active, setActive] = useState('home');

    useEffect(() => {
        const onScroll = () => {
            setScrolled(window.scrollY > 32);
            const ids = ['home', 'about', 'projects', 'github', 'contact'];
            for (let i = ids.length - 1; i >= 0; i--) {
                const el = document.getElementById(ids[i]);
                if (el && window.scrollY >= el.offsetTop - 120) { setActive(ids[i]); break; }
            }
        };
        window.addEventListener('scroll', onScroll, { passive: true });
        return () => window.removeEventListener('scroll', onScroll);
    }, []);

    const close = () => setMenuOpen(false);

    return (
        <motion.nav
            initial={{ y: -70, opacity: 0 }}
            animate={{ y: 0, opacity: 1 }}
            transition={{ duration: 0.45, ease: 'easeOut' }}
            style={{
                position: 'fixed', top: 0, left: 0, right: 0, zIndex: 1000,
                background: scrolled ? theme.navBg : 'transparent',
                backdropFilter: scrolled ? 'blur(20px)' : 'none',
                WebkitBackdropFilter: scrolled ? 'blur(20px)' : 'none',
                borderBottom: scrolled ? `1px solid ${theme.border}` : '1px solid transparent',
                transition: 'all 0.35s ease',
            }}
        >
            <div style={{ maxWidth: 1200, margin: '0 auto', padding: '0 20px' }}>
                <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', height: 62 }}>

                    {/* Logo */}
                    <a href="#home" onClick={e => { e.preventDefault(); scrollTo('#home'); }}
                        style={{ display: 'flex', alignItems: 'center', gap: 9, textDecoration: 'none', flexShrink: 0 }}>
                        <div style={{
                            width: 32, height: 32, borderRadius: 8,
                            background: 'linear-gradient(135deg, #7c3aed, #4f46e5)',
                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                            fontSize: 14, fontWeight: 800, color: 'white',
                            fontFamily: 'Plus Jakarta Sans, sans-serif',
                            boxShadow: '0 4px 12px rgba(124,58,237,0.38)',
                            letterSpacing: '-0.5px',
                        }}>B</div>
                        <span style={{ fontFamily: 'Plus Jakarta Sans, sans-serif', fontWeight: 700, fontSize: 16, color: theme.textPrimary }}>
                            Bara<span style={{ color: theme.accentText }}>.dev</span>
                        </span>
                    </a>

                    {/* Desktop Nav */}
                    <div className="nav-desktop" style={{ display: 'flex', alignItems: 'center', gap: 2 }}>
                        {navLinks.map(link => {
                            const isActive = active === link.href.replace('#', '');
                            return (
                                <a key={link.href} href={link.href}
                                    onClick={e => { e.preventDefault(); scrollTo(link.href); }}
                                    style={{
                                        padding: '6px 14px', borderRadius: 8, fontSize: 13.5, fontWeight: 500,
                                        color: isActive ? (isDark ? '#c4b5fd' : '#5b21b6') : theme.textSecondary,
                                        background: isActive ? theme.accentBg : 'transparent',
                                        border: `1px solid ${isActive ? theme.accentBorder : 'transparent'}`,
                                        textDecoration: 'none', cursor: 'pointer',
                                        transition: 'all 0.22s ease', whiteSpace: 'nowrap',
                                    }}
                                    onMouseEnter={e => {
                                        if (!isActive) {
                                            e.currentTarget.style.color = isDark ? '#c4b5fd' : '#5b21b6';
                                            e.currentTarget.style.background = theme.accentBg;
                                        }
                                    }}
                                    onMouseLeave={e => {
                                        if (!isActive) {
                                            e.currentTarget.style.color = theme.textSecondary;
                                            e.currentTarget.style.background = 'transparent';
                                        }
                                    }}
                                >{link.label}</a>
                            );
                        })}

                        {/* Theme Toggle */}
                        <button onClick={toggleTheme} aria-label="Ganti tema"
                            style={{
                                width: 34, height: 34, borderRadius: 8,
                                border: `1px solid ${theme.border}`,
                                background: theme.accentBg, cursor: 'pointer',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                color: theme.accentText, marginLeft: 4,
                                transition: 'all 0.25s ease', flexShrink: 0,
                            }}
                            onMouseEnter={e => { e.currentTarget.style.borderColor = theme.accentBorder; e.currentTarget.style.transform = 'rotate(18deg)'; }}
                            onMouseLeave={e => { e.currentTarget.style.borderColor = theme.border; e.currentTarget.style.transform = 'rotate(0deg)'; }}
                        >
                            {isDark ? <FiSun size={15} /> : <FiMoon size={15} />}
                        </button>

                        {/* CTA */}
                        <a href="#contact" onClick={e => { e.preventDefault(); scrollTo('#contact'); }}
                            style={{
                                marginLeft: 8, padding: '8px 18px', borderRadius: 8,
                                fontSize: 13.5, fontWeight: 600,
                                background: 'linear-gradient(135deg, #7c3aed, #4f46e5)',
                                color: 'white', textDecoration: 'none', cursor: 'pointer',
                                boxShadow: '0 3px 14px rgba(124,58,237,0.35)',
                                transition: 'all 0.25s ease', whiteSpace: 'nowrap',
                            }}
                            onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-2px)'; e.currentTarget.style.boxShadow = '0 8px 22px rgba(124,58,237,0.48)'; }}
                            onMouseLeave={e => { e.currentTarget.style.transform = 'translateY(0)'; e.currentTarget.style.boxShadow = '0 3px 14px rgba(124,58,237,0.35)'; }}
                        >
                            Hire Me
                        </a>
                    </div>

                    {/* Mobile Buttons */}
                    <div className="nav-mobile-btns" style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
                        <button onClick={toggleTheme} aria-label="Ganti tema"
                            style={{
                                width: 34, height: 34, borderRadius: 8, border: `1px solid ${theme.border}`,
                                background: theme.accentBg, cursor: 'pointer',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                color: theme.accentText, transition: 'all 0.25s ease',
                            }}
                        >
                            {isDark ? <FiSun size={15} /> : <FiMoon size={15} />}
                        </button>
                        <button onClick={() => setMenuOpen(o => !o)} aria-label="Menu"
                            style={{
                                width: 34, height: 34, borderRadius: 8,
                                border: `1px solid ${theme.accentBorder}`,
                                background: theme.accentBg, cursor: 'pointer',
                                display: 'flex', alignItems: 'center', justifyContent: 'center',
                                color: theme.accentText, transition: 'all 0.25s ease',
                            }}
                        >
                            {menuOpen ? <FiX size={16} /> : <FiMenu size={16} />}
                        </button>
                    </div>
                </div>
            </div>

            {/* Mobile Menu */}
            <AnimatePresence>
                {menuOpen && (
                    <motion.div
                        initial={{ opacity: 0, y: -8 }}
                        animate={{ opacity: 1, y: 0 }}
                        exit={{ opacity: 0, y: -8 }}
                        transition={{ duration: 0.2 }}
                        style={{
                            background: theme.navBg,
                            backdropFilter: 'blur(20px)',
                            WebkitBackdropFilter: 'blur(20px)',
                            borderTop: `1px solid ${theme.border}`,
                            padding: '10px 20px 16px',
                        }}
                    >
                        <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                            {navLinks.map(link => {
                                const isActive = active === link.href.replace('#', '');
                                return (
                                    <a key={link.href} href={link.href}
                                        onClick={e => { e.preventDefault(); scrollTo(link.href, close); }}
                                        style={{
                                            display: 'block', padding: '11px 14px', borderRadius: 10,
                                            fontSize: 14, fontWeight: 500,
                                            color: isActive ? (isDark ? '#c4b5fd' : '#5b21b6') : theme.textSecondary,
                                            background: isActive ? theme.accentBg : 'transparent',
                                            border: `1px solid ${isActive ? theme.accentBorder : 'transparent'}`,
                                            textDecoration: 'none', cursor: 'pointer',
                                            WebkitTapHighlightColor: 'transparent',
                                            transition: 'all 0.2s ease',
                                        }}
                                    >{link.label}</a>
                                );
                            })}
                            <a href="#contact"
                                onClick={e => { e.preventDefault(); scrollTo('#contact', close); }}
                                style={{
                                    display: 'block', padding: '12px 14px', borderRadius: 10, marginTop: 4,
                                    fontSize: 14, fontWeight: 700, textAlign: 'center',
                                    background: 'linear-gradient(135deg, #7c3aed, #4f46e5)', color: '#fff',
                                    textDecoration: 'none', cursor: 'pointer',
                                    boxShadow: '0 4px 14px rgba(124,58,237,0.3)',
                                    WebkitTapHighlightColor: 'transparent',
                                }}
                            >Hire Me</a>
                        </div>
                    </motion.div>
                )}
            </AnimatePresence>

            <style>{`
                .nav-desktop { display: none !important; }
                .nav-mobile-btns { display: flex !important; }
                @media (min-width: 768px) {
                    .nav-desktop { display: flex !important; }
                    .nav-mobile-btns { display: none !important; }
                }
            `}</style>
        </motion.nav>
    );
};

export default Navbar;