import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { FiX, FiGithub, FiExternalLink, FiChevronLeft, FiChevronRight } from 'react-icons/fi';
import { useTheme } from '../ThemeContext';

const modal = {
    hidden: { opacity: 0, scale: 0.95, y: 18 },
    visible: { opacity: 1, scale: 1, y: 0, transition: { type: 'spring', stiffness: 110, damping: 20 } },
    exit:    { opacity: 0, scale: 0.95, y: 18, transition: { duration: 0.18 } },
};
const backdrop = {
    hidden:  { opacity: 0 },
    visible: { opacity: 1 },
    exit:    { opacity: 0 },
};

const tagColors = {
    PHP:        { bg: 'rgba(119,123,180,0.12)', text: '#a5b4fc', border: 'rgba(119,123,180,0.25)' },
    CSS:        { bg: 'rgba(56,189,248,0.1)',   text: '#67e8f9',  border: 'rgba(56,189,248,0.22)' },
    Laravel:    { bg: 'rgba(255,45,32,0.1)',    text: '#fca5a5',  border: 'rgba(255,45,32,0.18)' },
    Python:     { bg: 'rgba(52,175,215,0.1)',   text: '#93c5fd',  border: 'rgba(52,175,215,0.22)' },
    HTML:       { bg: 'rgba(227,79,38,0.1)',    text: '#fdba74',  border: 'rgba(227,79,38,0.22)' },
    JavaScript: { bg: 'rgba(247,223,30,0.1)',   text: '#fde68a',  border: 'rgba(247,223,30,0.18)' },
    React:      { bg: 'rgba(97,218,251,0.1)',   text: '#a5f3fc',  border: 'rgba(97,218,251,0.22)' },
};

const ProjectModal = ({ project, onClose }) => {
    const { theme } = useTheme();
    const [idx, setIdx] = useState(0);
    if (!project) return null;

    const hasImages = project.images?.length > 0;
    const prev = () => setIdx(i => (i - 1 + project.images.length) % project.images.length);
    const next = () => setIdx(i => (i + 1) % project.images.length);

    return (
        <motion.div
            key="backdrop"
            style={{
                position: 'fixed', inset: 0, zIndex: 200,
                display: 'flex', alignItems: 'center', justifyContent: 'center',
                padding: '16px',
                background: 'rgba(0,0,0,0.72)',
                backdropFilter: 'blur(10px)',
            }}
            variants={backdrop}
            initial="hidden" animate="visible" exit="exit"
            onClick={onClose}
        >
            <motion.div
                key="modal"
                variants={modal}
                initial="hidden" animate="visible" exit="exit"
                onClick={e => e.stopPropagation()}
                style={{
                    background: theme.bg,
                    border: `1px solid ${theme.borderAccent}`,
                    borderRadius: 20,
                    width: '100%', maxWidth: 680,
                    maxHeight: '90vh', overflowY: 'auto',
                    position: 'relative',
                    boxShadow: `0 32px 80px rgba(0,0,0,0.55)`,
                }}
            >
                {/* Close */}
                <button onClick={onClose} aria-label="Tutup"
                    style={{
                        position: 'sticky', top: 14, float: 'right',
                        marginRight: 14, marginTop: 14, zIndex: 10,
                        width: 36, height: 36, borderRadius: 10,
                        background: theme.bgCard, border: `1px solid ${theme.border}`,
                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                        color: theme.textSecondary, cursor: 'pointer', transition: 'all 0.2s ease',
                    }}
                    onMouseEnter={e => { e.currentTarget.style.background = 'rgba(239,68,68,0.12)'; e.currentTarget.style.color = '#f87171'; }}
                    onMouseLeave={e => { e.currentTarget.style.background = theme.bgCard; e.currentTarget.style.color = theme.textSecondary; }}
                >
                    <FiX size={16} />
                </button>

                <div style={{ padding: '26px 26px 28px', clear: 'both' }}>
                    {/* Title */}
                    <div style={{ marginBottom: 14 }}>
                        {project.subtitle && (
                            <span style={{ fontSize: 11, color: theme.textMuted, fontWeight: 600, letterSpacing: 1.2, textTransform: 'uppercase' }}>
                                {project.subtitle}
                            </span>
                        )}
                        <h2 style={{
                            fontFamily: 'Plus Jakarta Sans, sans-serif',
                            fontSize: 'clamp(1.3rem, 3vw, 1.65rem)', fontWeight: 800,
                            color: theme.textPrimary, margin: '4px 0 0', lineHeight: 1.2,
                        }}>
                            {project.title}
                        </h2>
                    </div>

                    {/* Description */}
                    <p style={{ fontSize: 14, lineHeight: 1.72, color: theme.textSecondary, marginBottom: 24 }}>
                        {project.longDescription || project.description}
                    </p>

                    {/* Image Slider */}
                    {hasImages && (
                        <div style={{ marginBottom: 24 }}>
                            <div style={{ position: 'relative', borderRadius: 14, overflow: 'hidden', background: '#0a0f1e' }}>
                                <img
                                    key={idx}
                                    src={project.images[idx]}
                                    alt={`${project.title} screenshot ${idx + 1}`}
                                    style={{ width: '100%', height: 'auto', maxHeight: 320, objectFit: 'cover', display: 'block' }}
                                />
                                {project.images.length > 1 && (
                                    <>
                                        <button onClick={prev} aria-label="Sebelumnya" style={{
                                            position: 'absolute', left: 10, top: '50%', transform: 'translateY(-50%)',
                                            width: 32, height: 32, borderRadius: 8,
                                            background: 'rgba(7,9,26,0.8)', backdropFilter: 'blur(6px)',
                                            border: '1px solid rgba(255,255,255,0.1)',
                                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                                            color: 'white', cursor: 'pointer', zIndex: 5,
                                        }}>
                                            <FiChevronLeft size={16} />
                                        </button>
                                        <button onClick={next} aria-label="Berikutnya" style={{
                                            position: 'absolute', right: 10, top: '50%', transform: 'translateY(-50%)',
                                            width: 32, height: 32, borderRadius: 8,
                                            background: 'rgba(7,9,26,0.8)', backdropFilter: 'blur(6px)',
                                            border: '1px solid rgba(255,255,255,0.1)',
                                            display: 'flex', alignItems: 'center', justifyContent: 'center',
                                            color: 'white', cursor: 'pointer', zIndex: 5,
                                        }}>
                                            <FiChevronRight size={16} />
                                        </button>
                                        <div style={{ position: 'absolute', bottom: 10, left: '50%', transform: 'translateX(-50%)', display: 'flex', gap: 5, zIndex: 5 }}>
                                            {project.images.map((_, i) => (
                                                <button key={i} onClick={() => setIdx(i)} aria-label={`Gambar ${i + 1}`}
                                                    style={{
                                                        width: i === idx ? 18 : 7, height: 7, borderRadius: 4,
                                                        background: i === idx ? '#7c3aed' : 'rgba(255,255,255,0.3)',
                                                        border: 'none', cursor: 'pointer', transition: 'all 0.3s ease', padding: 0,
                                                    }}
                                                />
                                            ))}
                                        </div>
                                    </>
                                )}
                            </div>
                        </div>
                    )}

                    {/* Tags */}
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6, marginBottom: 22 }}>
                        {project.tags.map(tag => {
                            const c = tagColors[tag] || { bg: 'rgba(124,58,237,0.1)', text: '#c4b5fd', border: 'rgba(124,58,237,0.22)' };
                            return (
                                <span key={tag} style={{
                                    padding: '4px 12px', borderRadius: 100, fontSize: 11.5, fontWeight: 600,
                                    background: c.bg, color: c.text, border: `1px solid ${c.border}`,
                                }}>{tag}</span>
                            );
                        })}
                    </div>

                    {/* Actions */}
                    <div style={{ display: 'flex', flexWrap: 'wrap', gap: 10 }}>
                        {project.githubLink && project.githubLink !== '#' && (
                            <a href={project.githubLink} target="_blank" rel="noopener noreferrer"
                                className="btn-primary"
                                style={{ fontSize: 13.5, padding: '10px 20px' }}>
                                <FiGithub size={15} />
                                <span>Lihat GitHub</span>
                            </a>
                        )}
                        {project.liveDemoLink && project.liveDemoLink !== '#' && (
                            <a href={project.liveDemoLink} target="_blank" rel="noopener noreferrer"
                                className="btn-secondary"
                                style={{ fontSize: 13.5, padding: '10px 20px' }}>
                                <FiExternalLink size={14} />
                                Demo Langsung
                            </a>
                        )}
                    </div>
                </div>
            </motion.div>
        </motion.div>
    );
};

export default ProjectModal;