import React, { useRef, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Typed } from 'react-typed';
import { FiDownload, FiArrowRight, FiGithub, FiLinkedin } from 'react-icons/fi';
import { useTheme } from '../ThemeContext';

const container = {
    hidden: { opacity: 0 },
    visible: { opacity: 1, transition: { staggerChildren: 0.11, delayChildren: 0.18 } },
};
const item = {
    hidden: { y: 22, opacity: 0 },
    visible: { y: 0, opacity: 1, transition: { type: 'spring', stiffness: 85, damping: 16 } },
};

const Hero = () => {
    const { theme } = useTheme();
    const el = useRef(null);

    useEffect(() => {
        const typed = new Typed(el.current, {
            strings: ['Web Developer', 'Laravel Developer', 'React Developer', 'Full Stack Dev'],
            typeSpeed: 55, backSpeed: 32, backDelay: 1800, loop: true,
        });
        return () => typed.destroy();
    }, []);

    return (
        <section id="home" style={{
            minHeight: '100vh', display: 'flex', alignItems: 'center',
            padding: 'clamp(80px,12vh,120px) 0 clamp(40px,6vh,72px)',
            position: 'relative', overflow: 'hidden',
        }}>
            {/* Ambient blobs */}
            <div style={{
                position: 'absolute', width: 480, height: 480, borderRadius: '50%',
                background: 'radial-gradient(circle, rgba(124,58,237,0.08) 0%, transparent 70%)',
                top: '5%', left: '-8%', pointerEvents: 'none', filter: 'blur(40px)',
            }} />
            <div style={{
                position: 'absolute', width: 380, height: 380, borderRadius: '50%',
                background: 'radial-gradient(circle, rgba(59,130,246,0.06) 0%, transparent 70%)',
                bottom: '5%', right: '-5%', pointerEvents: 'none', filter: 'blur(40px)',
            }} />

            <motion.div initial="hidden" animate="visible" variants={container}
                style={{ maxWidth: 1200, margin: '0 auto', padding: '0 20px', width: '100%' }}>

                <div style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(0, 1fr))',
                    gap: 'clamp(28px, 5vw, 56px)',
                    alignItems: 'center',
                }}>
                    {/* Left: Text */}
                    <div style={{ minWidth: 0 }}>
                        <motion.div variants={item} style={{ marginBottom: 12 }}>
                            <span style={{
                                display: 'inline-flex', alignItems: 'center', gap: 7,
                                padding: '5px 14px', borderRadius: 100,
                                background: theme.accentBg, border: `1px solid ${theme.accentBorder}`,
                                fontSize: 11, fontWeight: 700, color: theme.accentText,
                                letterSpacing: 1.5, textTransform: 'uppercase',
                            }}>
                                Tersedia untuk bekerja
                            </span>
                        </motion.div>

                        <motion.h1 variants={item} style={{
                            fontFamily: 'Plus Jakarta Sans, sans-serif',
                            fontSize: 'clamp(2rem, 6vw, 3.8rem)', fontWeight: 800, lineHeight: 1.08,
                            color: theme.textPrimary, marginBottom: 12, letterSpacing: '-1.5px',
                        }}>
                            Bara Kusuma
                        </motion.h1>

                        <motion.div variants={item} style={{
                            fontSize: 'clamp(1rem, 2.8vw, 1.35rem)', fontWeight: 600,
                            marginBottom: 18, minHeight: 34,
                            display: 'flex', alignItems: 'center', gap: 8, flexWrap: 'wrap',
                        }}>
                            <span style={{ color: theme.textMuted }}>Seorang</span>
                            <span style={{
                                background: 'linear-gradient(135deg, #a78bfa, #818cf8, #38bdf8)',
                                WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', backgroundClip: 'text',
                            }}>
                                <span ref={el} />
                            </span>
                        </motion.div>

                        <motion.p variants={item} style={{
                            fontSize: 'clamp(14px, 1.8vw, 15.5px)', lineHeight: 1.75,
                            color: theme.textSecondary, marginBottom: 28, maxWidth: 440,
                        }}>
                            Pengembang web yang senang membangun produk digital yang cepat, bersih, dan menyenangkan untuk digunakan.
                        </motion.p>

                        {/* CTAs */}
                        <motion.div variants={item} style={{ display: 'flex', flexWrap: 'wrap', gap: 10, marginBottom: 26 }}>
                            <a href="#contact"
                                onClick={e => { e.preventDefault(); document.getElementById('contact')?.scrollIntoView({ behavior: 'smooth' }); }}
                                className="btn-primary"
                            >
                                <span>Hubungi Saya</span>
                                <FiArrowRight size={14} />
                            </a>
                            <a href={process.env.PUBLIC_URL + '/CV - Bara Kusuma.pdf'} download
                                className="btn-secondary"
                            >
                                <FiDownload size={14} />
                                <span>Unduh CV</span>
                            </a>
                        </motion.div>

                        {/* Social */}
                        <motion.div variants={item} style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
                            <span style={{ fontSize: 11.5, color: theme.textMuted, fontWeight: 600, letterSpacing: 1 }}>FIND ME</span>
                            {[
                                { href: 'https://github.com/BekaGensss', icon: <FiGithub size={16} />, label: 'GitHub' },
                                { href: 'https://id.linkedin.com/in/bara-kusuma-707067294', icon: <FiLinkedin size={16} />, label: 'LinkedIn' },
                            ].map(s => (
                                <a key={s.label} href={s.href} target="_blank" rel="noopener noreferrer" aria-label={s.label}
                                    style={{
                                        width: 36, height: 36, borderRadius: 9,
                                        background: theme.bgCard, border: `1px solid ${theme.border}`,
                                        display: 'flex', alignItems: 'center', justifyContent: 'center',
                                        color: theme.textMuted, textDecoration: 'none', transition: 'all 0.25s ease',
                                    }}
                                    onMouseEnter={e => {
                                        e.currentTarget.style.background = theme.accentBg;
                                        e.currentTarget.style.borderColor = theme.accentBorder;
                                        e.currentTarget.style.color = theme.accentText;
                                        e.currentTarget.style.transform = 'translateY(-2px)';
                                    }}
                                    onMouseLeave={e => {
                                        e.currentTarget.style.background = theme.bgCard;
                                        e.currentTarget.style.borderColor = theme.border;
                                        e.currentTarget.style.color = theme.textMuted;
                                        e.currentTarget.style.transform = 'translateY(0)';
                                    }}
                                >{s.icon}</a>
                            ))}
                        </motion.div>
                    </div>

                    {/* Right: Photo */}
                    <motion.div variants={item} style={{
                        display: 'flex', justifyContent: 'center', alignItems: 'center',
                    }}>
                        <div style={{ position: 'relative', display: 'inline-block' }} className="float-animation">
                            <div className="profile-ring">
                                <img
                                    src={process.env.PUBLIC_URL + '/profile.jpg'}
                                    alt="Bara Kusuma"
                                    style={{
                                        width: 'clamp(170px, 26vw, 260px)',
                                        height: 'clamp(170px, 26vw, 260px)',
                                        objectFit: 'cover', borderRadius: '50%',
                                        display: 'block', position: 'relative', zIndex: 1,
                                    }}
                                />
                            </div>
                        </div>
                    </motion.div>
                </div>

                {/* Scroll hint */}
                <motion.div
                    initial={{ opacity: 0 }} animate={{ opacity: 0.5 }}
                    transition={{ delay: 2.2 }}
                    style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 6, marginTop: 'clamp(28px,5vw,52px)' }}
                >
                    <span style={{ fontSize: 10, color: theme.textMuted, letterSpacing: 2.5, textTransform: 'uppercase', fontWeight: 600 }}>Scroll</span>
                    <div style={{ width: 20, height: 30, border: `1.5px solid ${theme.accentBorder}`, borderRadius: 10, display: 'flex', justifyContent: 'center', padding: 3 }}>
                        <motion.div animate={{ y: [0, 9, 0] }} transition={{ repeat: Infinity, duration: 1.4, ease: 'easeInOut' }}
                            style={{ width: 3.5, height: 6, borderRadius: 2, background: theme.accent }} />
                    </div>
                </motion.div>
            </motion.div>
        </section>
    );
};

export default Hero;